return [{
  json: {
    workflow_id: 'WF-020',
    vein: 'approval_vein',
    dossier_id: $json.dossier_id || 'TEST-DOSSIER',
    final_script_packet: $json.final_script_packet || {},
    approval_request_id: $json.approval_request_id || ('APPR-' + Date.now()),
    route_id: $json.route_id || 'ROUTE_PHASE1_STANDARD',
    execution_timestamp: new Date().toISOString()
  }
}];

const fp = $json.final_script_packet || {};
const q = fp.payload?.quality || {};
const s = fp.payload?.status || {};

const quality_summary = {
  grammar_score: q.grammar_score || 0,
  seo_readiness: q.seo_readiness || 0,
  tone_consistency: q.tone_consistency || 0,
  governance_compliance: q.governance_compliance || 'UNKNOWN',
  all_gates_passed: s.all_quality_gates_passed || false
};

const checks = [
  { item: 'Grammar >= 0.95', passed: quality_summary.grammar_score >= 0.95, score: quality_summary.grammar_score },
  { item: 'SEO readiness >= 0.85', passed: quality_summary.seo_readiness >= 0.85, score: quality_summary.seo_readiness },
  { item: 'Tone consistency >= 0.90', passed: quality_summary.tone_consistency >= 0.90, score: quality_summary.tone_consistency },
  { item: 'Governance approved', passed: quality_summary.governance_compliance === 'APPROVED' },
  { item: 'All quality gates passed', passed: quality_summary.all_gates_passed }
];

const approval_checklist = {
  checks: checks,
  checks_passed: checks.filter(c => c.passed).length,
  checks_total: 5,
  approval_recommended: quality_summary.all_gates_passed && quality_summary.governance_compliance === 'APPROVED'
};

return [{ json: { ...$json, quality_summary, approval_checklist, approval_phase: 'checklist_complete' } }];

const cl = $json.approval_checklist || {};
const fp = $json.final_script_packet || {};
const qs = $json.quality_summary || {};

const status = cl.approval_recommended ? 'PENDING' : 'ISSUES_FOUND';
const decision = cl.approval_recommended ? 'REQUIRES_DIRECTOR_REVIEW' : 'RETURN_FOR_REVISION';
const message = cl.approval_recommended
  ? 'Script meets quality gates. Recommend approval for publication.'
  : 'Quality gates not met. Recommend return to refinement phase.';

const approval_queue_entry = {
  approval_request_id: $json.approval_request_id,
  script_packet_id: fp.instance_id || 'UNKNOWN',
  dossier_ref: $json.dossier_id,
  status: status,
  decision: decision,
  owner_director: 'Krishna',
  supporting_directors: ['Vyasa', 'Saraswati', 'Durga'],
  approval_criteria: { grammar_minimum: 0.95, seo_readiness_minimum: 0.85, tone_consistency_minimum: 0.90 },
  actual_scores: { grammar: qs.grammar_score, seo_readiness: qs.seo_readiness, tone_consistency: qs.tone_consistency, governance_compliance: qs.governance_compliance },
  approval_message: message,
  decision_required_by: new Date(Date.now() + 86400000).toISOString(),
  created_at: new Date().toISOString()
};

return [{ json: { ...$json, approval_queue_entry, approval_phase: 'queue_entry_complete' } }];

const aqe = $json.approval_queue_entry || {};
const fp = $json.final_script_packet || {};
const cl = $json.approval_checklist || {};

const approval_decision_packet = {
  instance_id: 'ADP-' + Date.now(),
  artifact_family: 'approval_decision_packet',
  schema_version: '1.0.0',
  producer_workflow: 'SE-N8N-WF-020-Final-Approval',
  dossier_ref: $json.dossier_id,
  created_at: new Date().toISOString(),
  status: 'PENDING_DIRECTOR_DECISION',
  payload: {
    approval_request: {
      approval_request_id: aqe.approval_request_id,
      script_packet_reference: fp.instance_id || 'UNKNOWN',
      approval_status: aqe.status,
      initial_recommendation: aqe.decision
    },
    context: {
      owner_director: aqe.owner_director,
      supporting_directors: aqe.supporting_directors,
      decision_deadline: aqe.decision_required_by,
      approval_route: 'ROUTE_PHASE1_STANDARD'
    },
    evidence: {
      quality_checklist: cl.checks || [],
      criteria_met: cl.approval_recommended,
      actual_quality_scores: aqe.actual_scores
    },
    quality: {
      grammar_compliance: { required_minimum: 0.95, actual_score: aqe.actual_scores?.grammar, compliant: (aqe.actual_scores?.grammar >= 0.95) },
      seo_compliance: { required_minimum: 0.85, actual_score: aqe.actual_scores?.seo_readiness, compliant: (aqe.actual_scores?.seo_readiness >= 0.85) },
      tone_compliance: { required_minimum: 0.90, actual_score: aqe.actual_scores?.tone_consistency, compliant: (aqe.actual_scores?.tone_consistency >= 0.90) },
      governance_compliance: aqe.actual_scores?.governance_compliance,
      overall_recommendation: aqe.approval_message
    },
    status: {
      approval_status: aqe.status,
      pending_decision_from: aqe.owner_director,
      possible_decisions: ['APPROVED_FOR_PUBLISHING', 'REJECTED_RETURN_TO_REFINEMENT', 'APPROVED_WITH_MODIFICATIONS'],
      next_workflow_on_approval: 'WF-300',
      next_workflow_on_rejection: 'WF-021'
    }
  }
};

return [{ json: approval_decision_packet }];

const p = $json.payload || {};
const errors = [];

if (!p.approval_request?.approval_request_id) errors.push('Missing approval_request_id');
if (!p.context?.owner_director) errors.push('Missing owner_director');
if (!Array.isArray(p.evidence?.quality_checklist)) errors.push('Missing quality_checklist array');
if (!p.quality?.overall_recommendation) errors.push('Missing overall_recommendation');
if (!Array.isArray(p.status?.possible_decisions)) errors.push('Missing possible_decisions array');

if (errors.length > 0) throw new Error('Approval packet validation failed: ' + errors.join('; '));

return [{ json: { ...$json, validation_status: 'PASSED', validation_timestamp: new Date().toISOString() } }];

const p = $json.payload || {};
const aqe = $json.approval_queue_entry || {};

return [{
  json: {
    workflow_id: 'WF-020',
    execution_status: 'SUCCESS',
    approval_request_id: p.approval_request?.approval_request_id,
    approval_status: p.status?.approval_status,
    pending_decision_from: p.context?.owner_director,
    initial_recommendation: p.quality?.overall_recommendation,
    approval_packet: $json,
    dossier_delta: {
      namespace: 'approval',
      mutation_type: 'append_to_array',
      target: 'dossier.approval.pending_approvals',
      value: {
        approval_request_id: aqe.approval_request_id,
        packet_instance_id: $json.instance_id,
        owner_director: aqe.owner_director,
        decision_deadline: aqe.decision_required_by,
        status: 'PENDING',
        timestamp: new Date().toISOString()
      },
      audit_entry: {
        timestamp: new Date().toISOString(),
        workflow_id: 'WF-020',
        operation: 'QUEUE_APPROVAL_REQUEST',
        lineage_intact: true,
        sourced_from: $json.dossier_ref
      }
    },
    decision: 'APPROVAL_QUEUED_FOR_DIRECTOR_DECISION'
  }
}];
